(function(w){"use strict";const ID="linear-equation";function compute(x){const a=Number(x.a),b=Number(x.b);if(!Number.isFinite(a)||!Number.isFinite(b))return{error:"a와 b에 숫자를 입력해 주세요."};if(a===0&&b===0)return{type:"infinite",label:"모든 실수가 해입니다."};if(a===0)return{type:"none",label:"해가 없습니다."};const value=-b/a;return{type:"unique",value,label:"x = "+value}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">ax + b = 0 형태의 일차방정식을 풉니다.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-linear-a">a</label><input id="hm-linear-a" class="hm-calc-input" inputmode="decimal" placeholder="예: 2"></div><div class="hm-calc-field"><label for="hm-linear-b">b</label><input id="hm-linear-b" class="hm-calc-input" inputmode="decimal" placeholder="예: -6"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">방정식 풀기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:a.value,b:b.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const value=r.type==="unique"?"x = "+api.formatNumber(r.value,12):r.label;api.setResult(res,api.resultCard("해",value));});reset.addEventListener("click",()=>{a.value=b.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
